mapper.select:
	/* com.erns.coching.member.mapper.AdminMemberDAO.getList */

	SELECT * FROM (
		SELECT A.*,ROW_NUMBER() OVER () AS RN, COUNT(*) OVER() TOTAL FROM (
			SELECT

			FROM t_memb_admin_inf AA




		) A
	)

    	WHERE RN BETWEEN (#{offset} + 1) AND #{offset} + #{rowSize}

/* com.erns.coching.member.mapper.AdminMemberDAO.getListCount */

SELECT count(*) AS CNT
FROM t_memb_admin_inf AA

mapper.insert:
/* com.erns.coching.member.mapper.AdminMemberDAO.insert */


	SELECT
		SQ_QP_MEMB_ADMIN_INF.NEXTVAL AS seq
		, DBMS_RANDOM.STRING('X',  24) AS salt
	FROM DUAL


INSERT INTO t_memb_admin_inf (
	  MEMB_SEQ
	, MEMB_ID
	, PSWD
	, MEMB_SALT
	, MEMB_NAME
	, MEMB_PHONE
	, MEMB_EMAIL
	, PSWD_CHNG_DTTM
	, PSWD_ERR_CNT
	, USE_YN

	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM
) VALUES (
	  #{seq		, jdbcType=INTEGER}
	, #{userId	, jdbcType=VARCHAR}
	, SF_QP_FN_PASSWD(#{password, jdbcType=VARCHAR}, #{salt,jdbcType=VARCHAR})
	, #{salt	, jdbcType=VARCHAR}
	, #{userName, jdbcType=VARCHAR}
	, #{phone	, jdbcType=VARCHAR}
	, #{email	, jdbcType=VARCHAR}
	, now()	/* 비밀번호 변경일 */
	, 0			/* 비밀번호 오류 횟수 */
	, COALESCE(#{useYn	 , jdbcType=CHAR}, 'Y')

	, #{rgtrSeq	, jdbcType=INTEGER}
	, now()
	, #{chnrSeq	, jdbcType=INTEGER}
	, now()
)

mapper.select:
/* com.erns.coching.member.mapper.AdminMemberDAO.loadWithCheckingPasswd */

SELECT

FROM t_memb_admin_inf AA

	AND AA.MEMB_SEQ  = #{seq, jdbcType=INTEGER}
	AND AA.PSWD = ENCODE(DIGEST(#{pswd, jdbcType=VARCHAR} || SALT, 'sha512'), 'hex')

mapper.update:
/* com.erns.coching.member.mapper.AdminMemberDAO.update */
UPDATE t_memb_admin_inf SET
	  MEMB_NAME 	= #{userName	, jdbcType=VARCHAR}
    , MEMB_PHONE 	= #{phone		, jdbcType=VARCHAR}
    , MEMB_EMAIL 	= #{email		, jdbcType=VARCHAR}

    , CHNR 			= #{chnrSeq	, jdbcType=INTEGER}
    , CHNG_DTTM 	= now()

	AND MEMB_SEQ 	= #{seq, jdbcType=INTEGER}

mapper.insert:
	/* com.erns.coching.member.mapper.AdminMemberDAO.updatePwd */


		SELECT DBMS_RANDOM.STRING('X',  24) AS SALT FROM DUAL


	UPDATE t_memb_admin_inf SET
	 	  PSWD 		= ENCODE(DIGEST(#{pswd, jdbcType=VARCHAR} || SALT, 'sha512'), 'hex')
		, MEMB_SALT		= #{salt, jdbcType=VARCHAR}
    	, PSWD_CHNG_DTTM 	= now()
    	, PSWD_ERR_CNT	= 0
    	, PSWD_INIT_YN	= 'N'


		AND MEMB_SEQ = #{seq, jdbcType=INTEGER}

mapper.delete:
/* com.erns.coching.member.mapper.AdminMemberDAO.delete */

DELETE FROM t_memb_admin_inf

	AND MEMB_SEQ = #{seq , jdbcType=INTEGER}

mapper.update:
/* com.erns.coching.member.mapper.AdminMemberDAO.updateUseYn */

UPDATE t_memb_admin_inf SET
      USE_YN		= #{useYn		, jdbcType=CHAR}
    , UDT_ID 		= #{udtId		, jdbcType=INTEGER}
    , UDT_DATE 		= now()

	AND MEMB_SEQ = #{userSeq, jdbcType=INTEGER}

mapper.select:
/* com.erns.coching.member.mapper.AdminMemberDAO.selectBackOfficeUserList */ SELECT AA.MEMB_SEQ , AA.MEMB_ID , AA.MEMB_NAME , AA.PHONE , AA.EMAIL , AA.ZIPCODE , AA.USE_YN , TO_CHAR(AA.PWD_CHNG_DATE, 'YYYY-MM-DD HH24:mi:SS') AS PWD_CHNG_DATE , AA.PWD_ERR_COUNT , AA.PLATFORM_TYPE , AA.REG_ID , TO_CHAR(AA.REG_DATE, 'YYYY-MM-DD HH24:mi:SS') AS REG_DATE , AA.UDT_ID , TO_CHAR(AA.UDT_DATE, 'YYYY-MM-DD HH24:mi:SS') AS UDT_DATE
, BB.DEPT , BB.RANK
FROM t_memb_admin_inf AA JOIN t_memb_admin_inf_BACKOFFICE_INFO BB ON AA.MEMB_SEQ = BB.MEMB_ID
ORDER BY ${sortColumn} DESC
LIMIT #{rowSize} OFFSET #{offset}
